from fastapi import APIRouter, Depends
from sqlalchemy.orm import Session

from app.api.deps import DBSession
from app.schemas.report import ReportCreate, ReportResponse
from app.services.report import create_report

router = APIRouter(prefix="/reports")


@router.post("", response_model=ReportResponse, status_code=201)
def submit_report(data: ReportCreate, db: Session = Depends(DBSession)):
    """Submit a housekeeping report with photos and voice note."""
    return create_report(db, data)

/* ============================================================
   HOUSEKEEPING REPORTER – Mobile-First, Elderly-Friendly UI
   Font: Nunito | Palette: #4A90FF blue + warm whites
   ============================================================ */

/* ── Reset & Root ── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --blue:        #4A90FF;
  --blue-dark:   #2D74E7;
  --blue-light:  #E8F4FF;
  --blue-pale:   #F0F7FF;
  --white:       #FFFFFF;
  --bg:          #F4F7FB;
  --text:        #111827;
  --text-mid:    #374151;
  --text-soft:   #6B7280;
  --error:       #EF4444;
  --success:     #10B981;
  --radius-xl:   20px;
  --radius-lg:   16px;
  --radius-md:   12px;
  --shadow-card: 0 4px 20px rgba(74,144,255,0.12);
  --shadow-btn:  0 6px 20px rgba(74,144,255,0.35);
  --font:        'Nunito', system-ui, sans-serif;
  --transition:  0.28s cubic-bezier(0.4, 0, 0.2, 1);
}

html, body {
  height: 100%;
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  -webkit-tap-highlight-color: transparent;
  overscroll-behavior: none;
}

/* ── App Shell ── */
#app {
  position: fixed;
  inset: 0;
  overflow: hidden;
}

/* ── Screens ── */
.screen {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  opacity: 0;
  pointer-events: none;
  transform: translateY(16px);
  transition: opacity var(--transition), transform var(--transition);
  will-change: opacity, transform;
}

.screen.active {
  opacity: 1;
  pointer-events: all;
  transform: translateY(0);
}

/* ============================================================
   SCREEN 1 – NHẬP MÃ PHÒNG
   ============================================================ */
#screen-room {
  background: linear-gradient(160deg, #EEF6FF 0%, #FFFFFF 55%, var(--bg) 100%);
  align-items: center;
  justify-content: center;
  padding: 32px 24px 48px;
}

.screen-inner {
  width: 100%;
  max-width: 400px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0;
}

.brand-icon {
  font-size: 64px;
  line-height: 1;
  margin-bottom: 16px;
  filter: drop-shadow(0 4px 12px rgba(74,144,255,0.2));
  animation: float 3s ease-in-out infinite;
}

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50%       { transform: translateY(-6px); }
}

.screen-title {
  font-size: 26px;
  font-weight: 800;
  color: var(--text);
  text-align: center;
  margin-bottom: 28px;
  letter-spacing: -0.3px;
}

.input-card {
  width: 100%;
  background: var(--white);
  border-radius: var(--radius-xl);
  box-shadow: var(--shadow-card);
  padding: 20px 20px 16px;
  margin-bottom: 24px;
}

.room-input {
  width: 100%;
  height: 64px;
  border: 2.5px solid #D1E9FF;
  border-radius: var(--radius-lg);
  background: var(--blue-pale);
  font-family: var(--font);
  font-size: 28px;
  font-weight: 700;
  color: var(--text);
  text-align: center;
  letter-spacing: 2px;
  outline: none;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.room-input::placeholder {
  color: #B8CEEA;
  font-weight: 600;
  letter-spacing: 1px;
}

.room-input:focus {
  border-color: var(--blue);
  box-shadow: 0 0 0 4px rgba(74,144,255,0.15);
  background: var(--white);
}

.input-hint {
  margin-top: 10px;
  font-size: 14px;
  font-weight: 600;
  color: var(--text-soft);
  text-align: center;
}

/* ============================================================
   SHARED – PRIMARY BUTTON
   ============================================================ */
.btn-primary {
  width: 100%;
  height: 56px;
  border-radius: 28px;
  background: var(--blue);
  color: var(--white);
  border: none;
  font-family: var(--font);
  font-size: 18px;
  font-weight: 800;
  letter-spacing: 0.3px;
  cursor: pointer;
  box-shadow: var(--shadow-btn);
  transition: transform 0.15s, background 0.15s, box-shadow 0.15s, opacity 0.15s;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
}

.btn-primary:active {
  transform: scale(0.97);
  background: var(--blue-dark);
  box-shadow: 0 2px 10px rgba(74,144,255,0.25);
}

.btn-primary:disabled {
  background: #B0C4DE;
  box-shadow: none;
  cursor: not-allowed;
  opacity: 0.75;
}

.btn-secondary {
  width: 100%;
  height: 48px;
  border-radius: 24px;
  background: var(--white);
  color: var(--blue);
  border: 2px solid var(--blue);
  font-family: var(--font);
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  transition: transform 0.15s, background 0.15s;
  display: flex;
  align-items: center;
  justify-content: center;
}

.btn-secondary:active {
  transform: scale(0.97);
  background: var(--blue-light);
}

/* ============================================================
   SCREEN 2 – CAMERA
   ============================================================ */
#screen-camera {
  background: #000;
  display: flex;
  flex-direction: column;
}

.camera-header {
  flex: 0 0 auto;
  padding: 16px 20px 10px;
  background: linear-gradient(to bottom, rgba(0,0,0,0.75), transparent);
  position: relative;
  z-index: 2;
  text-align: center;
}

.room-badge {
  font-size: 20px;
  font-weight: 900;
  color: var(--white);
  letter-spacing: 2px;
  text-shadow: 0 2px 8px rgba(0,0,0,0.4);
}

.camera-subtitle {
  font-size: 13px;
  font-weight: 600;
  color: rgba(255,255,255,0.8);
  margin-top: 2px;
}

.camera-view-wrap {
  flex: 1;
  position: relative;
  overflow: hidden;
  background: #1a1a1a;
  display: flex;
  align-items: center;
  justify-content: center;
}

#camera-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.camera-no-access {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  padding: 32px;
  text-align: center;
  color: rgba(255,255,255,0.75);
}

.camera-no-icon { font-size: 48px; }

.camera-no-access p {
  font-size: 15px;
  font-weight: 600;
  line-height: 1.5;
}

.camera-controls {
  flex: 0 0 auto;
  background: linear-gradient(to top, rgba(0,0,0,0.85), transparent);
  padding: 12px 20px 28px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}

.photo-counter {
  font-size: 16px;
  font-weight: 800;
  color: var(--white);
  background: rgba(74,144,255,0.7);
  padding: 4px 16px;
  border-radius: 20px;
  letter-spacing: 1px;
}

/* Shutter Button */
.btn-shutter {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  border: 4px solid rgba(255,255,255,0.9);
  background: transparent;
  cursor: pointer;
  padding: 6px;
  transition: transform 0.12s, border-color 0.12s;
  display: flex;
  align-items: center;
  justify-content: center;
}

.btn-shutter:active { transform: scale(0.9); }

.shutter-ring {
  width: 100%;
  height: 100%;
  border-radius: 50%;
  border: 3px solid transparent;
  display: flex;
  align-items: center;
  justify-content: center;
}

.shutter-dot {
  width: 52px;
  height: 52px;
  border-radius: 50%;
  background: var(--white);
  transition: background 0.12s;
}

.btn-shutter:active .shutter-dot { background: rgba(255,255,255,0.7); }

/* Thumbnails */
.thumbnail-row {
  display: flex;
  gap: 8px;
  justify-content: center;
  min-height: 64px;
  align-items: center;
}

.thumb-item {
  position: relative;
  width: 60px;
  height: 60px;
  border-radius: var(--radius-md);
  overflow: visible;
  animation: pop-in 0.2s ease-out;
}

@keyframes pop-in {
  from { transform: scale(0.6); opacity: 0; }
  to   { transform: scale(1);   opacity: 1; }
}

.thumb-item img {
  width: 60px;
  height: 60px;
  object-fit: cover;
  border-radius: var(--radius-md);
  border: 2px solid rgba(255,255,255,0.6);
}

.thumb-delete {
  position: absolute;
  top: -8px;
  right: -8px;
  width: 24px;
  height: 24px;
  border-radius: 50%;
  background: var(--error);
  color: var(--white);
  border: 2px solid var(--white);
  font-size: 11px;
  font-weight: 800;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  line-height: 1;
  transition: transform 0.12s;
  padding: 0;
}

.thumb-delete:active { transform: scale(0.85); }

/* ============================================================
   SCREEN 3 – REPORT
   ============================================================ */
#screen-report {
  background: var(--bg);
  display: flex;
  flex-direction: column;
}

.report-scroll {
  flex: 1;
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
  padding: 20px 16px 0;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.report-header-card {
  background: var(--blue);
  border-radius: var(--radius-xl);
  padding: 18px 20px;
  box-shadow: var(--shadow-btn);
}

.report-room-row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.room-icon { font-size: 22px; }

.report-room-text {
  font-size: 22px;
  font-weight: 900;
  color: var(--white);
  letter-spacing: 1.5px;
}

.report-tagline {
  margin-top: 6px;
  font-size: 13px;
  font-weight: 600;
  color: rgba(255,255,255,0.8);
}

.section-card {
  background: var(--white);
  border-radius: var(--radius-xl);
  padding: 16px 16px;
  box-shadow: var(--shadow-card);
}

.section-label {
  font-size: 15px;
  font-weight: 700;
  color: var(--text-mid);
  margin-bottom: 12px;
}

.report-thumb-row {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  padding-bottom: 4px;
  -webkit-overflow-scrolling: touch;
  min-height: 80px;
  align-items: center;
}

.report-thumb-row::-webkit-scrollbar { height: 4px; }
.report-thumb-row::-webkit-scrollbar-track { background: var(--blue-pale); border-radius: 2px; }
.report-thumb-row::-webkit-scrollbar-thumb { background: var(--blue); border-radius: 2px; }

.report-thumb {
  width: 80px;
  height: 80px;
  object-fit: cover;
  border-radius: var(--radius-md);
  flex-shrink: 0;
  border: 2px solid var(--blue-light);
}

/* ── Voice Card ── */
.voice-card {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.btn-mic {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  background: var(--blue-light);
  border: 3px solid var(--blue);
  color: var(--blue);
  cursor: pointer;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 4px;
  transition: background 0.2s, transform 0.15s, box-shadow 0.2s;
  margin-bottom: 10px;
}

.btn-mic:active { transform: scale(0.93); }

.btn-mic.recording {
  background: #FEE2E2;
  border-color: var(--error);
  color: var(--error);
  box-shadow: 0 0 0 8px rgba(239,68,68,0.12), 0 0 0 16px rgba(239,68,68,0.06);
  animation: mic-pulse 1.2s ease-in-out infinite;
}

@keyframes mic-pulse {
  0%, 100% { box-shadow: 0 0 0 6px rgba(239,68,68,0.15), 0 0 0 14px rgba(239,68,68,0.06); }
  50%       { box-shadow: 0 0 0 10px rgba(239,68,68,0.2), 0 0 0 20px rgba(239,68,68,0.08); }
}

.mic-icon {
  width: 28px;
  height: 28px;
}

.mic-label {
  font-size: 10px;
  font-weight: 700;
  white-space: nowrap;
}

/* Voice waves animation */
.voice-waves {
  display: flex;
  align-items: center;
  gap: 4px;
  height: 28px;
  opacity: 0;
  transition: opacity 0.3s;
  margin-bottom: 10px;
}

.voice-waves.active {
  opacity: 1;
}

.voice-waves span {
  display: block;
  width: 4px;
  background: var(--error);
  border-radius: 2px;
  animation: wave 1s ease-in-out infinite;
}

.voice-waves span:nth-child(1) { height: 8px;  animation-delay: 0s; }
.voice-waves span:nth-child(2) { height: 16px; animation-delay: 0.1s; }
.voice-waves span:nth-child(3) { height: 24px; animation-delay: 0.2s; }
.voice-waves span:nth-child(4) { height: 16px; animation-delay: 0.3s; }
.voice-waves span:nth-child(5) { height: 8px;  animation-delay: 0.4s; }

@keyframes wave {
  0%, 100% { transform: scaleY(0.5); }
  50%       { transform: scaleY(1.2); }
}

.voice-textarea {
  width: 100%;
  border: 2px solid #E5EEF9;
  border-radius: var(--radius-md);
  background: var(--blue-pale);
  font-family: var(--font);
  font-size: 15px;
  font-weight: 600;
  color: var(--text);
  padding: 12px 14px;
  resize: vertical;
  outline: none;
  transition: border-color 0.2s;
  min-height: 80px;
  line-height: 1.6;
}

.voice-textarea:focus {
  border-color: var(--blue);
  background: var(--white);
}

.voice-textarea::placeholder {
  color: #A0B3CC;
  font-weight: 500;
}

.bottom-spacer { height: 90px; }

/* Sticky submit */
.sticky-bottom {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 12px 20px 28px;
  background: linear-gradient(to top, var(--bg) 60%, transparent);
  pointer-events: none;
}

.sticky-bottom .btn-primary {
  pointer-events: all;
  font-size: 17px;
  letter-spacing: 1px;
}

/* ============================================================
   SCREEN 4 – SUCCESS
   ============================================================ */
#screen-success {
  background: linear-gradient(160deg, #EEF6FF 0%, #FFFFFF 60%, var(--bg) 100%);
  align-items: center;
  justify-content: center;
  padding: 32px 24px 48px;
}

.success-wrap {
  width: 100%;
  max-width: 360px;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  gap: 0;
}

.success-circle {
  width: 100px;
  height: 100px;
  margin-bottom: 24px;
  animation: success-pop 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) both;
}

.success-circle svg { width: 100%; height: 100%; }

@keyframes success-pop {
  from { transform: scale(0); opacity: 0; }
  to   { transform: scale(1); opacity: 1; }
}

.success-title {
  font-size: 28px;
  font-weight: 900;
  color: var(--text);
  line-height: 1.25;
  margin-bottom: 12px;
  letter-spacing: -0.5px;
}

.success-sub {
  font-size: 16px;
  font-weight: 700;
  color: var(--blue);
  background: var(--blue-light);
  padding: 8px 20px;
  border-radius: 20px;
  margin-bottom: 20px;
}

.success-countdown {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-soft);
  margin-bottom: 24px;
}

/* ============================================================
   TOAST
   ============================================================ */
.toast {
  position: fixed;
  bottom: 32px;
  left: 50%;
  transform: translateX(-50%) translateY(80px);
  background: #1F2937;
  color: var(--white);
  padding: 12px 24px;
  border-radius: 24px;
  font-size: 14px;
  font-weight: 700;
  max-width: calc(100% - 48px);
  text-align: center;
  z-index: 9999;
  opacity: 0;
  transition: opacity 0.25s, transform 0.25s;
  pointer-events: none;
  box-shadow: 0 8px 24px rgba(0,0,0,0.25);
}

.toast.show {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

/* ============================================================
   RESPONSIVE TWEAKS
   ============================================================ */
@media (min-height: 750px) {
  .brand-icon { font-size: 72px; margin-bottom: 20px; }
  .screen-title { font-size: 28px; }
  .btn-primary { height: 60px; font-size: 19px; }
}

@media (max-height: 600px) {
  .brand-icon { font-size: 44px; margin-bottom: 8px; }
  .screen-title { font-size: 22px; margin-bottom: 16px; }
  .success-circle { width: 80px; height: 80px; }
}

/* ============================================================
   HOUSEKEEPING REPORTER – Mobile-First, Elderly-Friendly UI
   Font: Nunito | Palette: #4A90FF blue + warm whites
   ============================================================ */

/* ── Reset & Root ── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --blue:        #4A90FF;
  --blue-dark:   #2D74E7;
  --blue-light:  #E8F4FF;
  --blue-pale:   #F0F7FF;
  --white:       #FFFFFF;
  --bg:          #F4F7FB;
  --text:        #111827;
  --text-mid:    #374151;
  --text-soft:   #6B7280;
  --error:       #EF4444;
  --radius-xl:   20px;
  --radius-lg:   16px;
  --radius-md:   12px;
  --shadow-card: 0 4px 20px rgba(74,144,255,0.12);
  --shadow-btn:  0 6px 20px rgba(74,144,255,0.35);
  --font:        'Nunito', system-ui, sans-serif;
  --transition:  0.28s cubic-bezier(0.4, 0, 0.2, 1);
}

html, body {
  height: 100%;
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  -webkit-tap-highlight-color: transparent;
  overscroll-behavior: none;
}

/* ── App Shell ── */
#app {
  position: fixed;
  inset: 0;
  overflow: hidden;
}

/* ── Screens ── */
.screen {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  opacity: 0;
  pointer-events: none;
  transform: translateY(16px);
  transition: opacity var(--transition), transform var(--transition);
  will-change: opacity, transform;
}

.screen.active {
  opacity: 1;
  pointer-events: all;
  transform: translateY(0);
}

