#screen-success {
  background: linear-gradient(160deg, #EEF6FF 0%, #FFFFFF 60%, var(--bg) 100%);
  align-items: center;
  justify-content: center;
  padding: 32px 24px 48px;
}

.success-wrap {
  width: 100%;
  max-width: 360px;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
}

.success-circle {
  width: 100px;
  height: 100px;
  margin-bottom: 24px;
  animation: success-pop 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) both;
}

.success-circle svg { width: 100%; height: 100%; }

@keyframes success-pop {
  from { transform: scale(0); opacity: 0; }
  to   { transform: scale(1); opacity: 1; }
}

.success-title {
  font-size: 28px;
  font-weight: 900;
  color: var(--text);
  line-height: 1.25;
  margin-bottom: 12px;
  letter-spacing: -0.5px;
}

.success-sub {
  font-size: 16px;
  font-weight: 700;
  color: var(--blue);
  background: var(--blue-light);
  padding: 8px 20px;
  border-radius: 20px;
  margin-bottom: 20px;
}

.success-countdown {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-soft);
  margin-bottom: 24px;
}

/* ============================================================
   TOAST
   ============================================================ */
.toast {
  position: fixed;
  bottom: 32px;
  left: 50%;
  transform: translateX(-50%) translateY(80px);
  background: #1F2937;
  color: var(--white);
  padding: 12px 24px;
  border-radius: 24px;
  font-size: 14px;
  font-weight: 700;
  max-width: calc(100% - 48px);
  text-align: center;
  z-index: 9999;
  opacity: 0;
  transition: opacity 0.25s, transform 0.25s;
  pointer-events: none;
  box-shadow: 0 8px 24px rgba(0,0,0,0.25);
}

.toast.show {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

/* ============================================================
   RESPONSIVE
   ============================================================ */
@media (min-height: 750px) {
  .brand-icon { font-size: 72px; margin-bottom: 20px; }
  .screen-title { font-size: 28px; }
  .btn-primary { height: 60px; font-size: 19px; }
}

@media (max-height: 580px) {
  .brand-icon { font-size: 44px; margin-bottom: 8px; }
  .screen-title { font-size: 22px; margin-bottom: 16px; }
  .success-circle { width: 72px; height: 72px; }
  .success-title { font-size: 22px; }
}
