/**
 * Housekeeping Reporter – App Logic
 * Flow: Room Input → Camera → Report → Success
 */

// ── App State ──────────────────────────────────────────────
const state = {
  roomId: '',
  photos: [],      // [{ blob, dataUrl, fileUrl }]
  voiceText: '',
  mediaStream: null,
  isRecording: false,
  recognition: null,
  isSubmitting: false,
  countdownTimer: null,
};

// ── Init ───────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  setupRoomScreen();
  setupCameraScreen();
  setupReportScreen();
  setupSuccessScreen();
  // Auto-focus room input
  setTimeout(() => document.getElementById('room-input').focus(), 150);
});

// ── Navigation ─────────────────────────────────────────────
function showScreen(name) {
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  document.getElementById(`screen-${name}`).classList.add('active');
}

// ══════════════════════════════════════════════════════════
//  SCREEN 1 – NHẬP MÃ PHÒNG
// ══════════════════════════════════════════════════════════
function setupRoomScreen() {
  const input = document.getElementById('room-input');
  const btn   = document.getElementById('btn-continue-room');

  input.addEventListener('input', () => {
    btn.disabled = input.value.trim().length === 0;
  });

  input.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && !btn.disabled) btn.click();
  });

  btn.addEventListener('click', () => {
    const value = input.value.trim();
    if (!value) { showToast('Vui lòng nhập mã phòng'); return; }
    state.roomId  = value.toUpperCase();
    state.photos  = [];
    state.voiceText = '';
    goToCamera();
  });
}

// ══════════════════════════════════════════════════════════
//  SCREEN 2 – CAMERA
// ══════════════════════════════════════════════════════════
function setupCameraScreen() {
  document.getElementById('btn-shutter').addEventListener('click', capturePhoto);
  document.getElementById('btn-skip-camera').addEventListener('click', () => {
    if (state.photos.length === 0) { showToast('Vui lòng chụp ít nhất 1 ảnh'); return; }
    stopCamera();
    goToReport();
  });
}

async function goToCamera() {
  document.getElementById('camera-room-label').textContent = `PHÒNG ${state.roomId}`;
  renderCameraThumbs();
  updateCounter();
  showScreen('camera');
  await initCamera();
}

async function initCamera() {
  const video   = document.getElementById('camera-video');
  const noAccess = document.getElementById('camera-no-access');
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 }, height: { ideal: 720 } },
      audio: false,
    });
    state.mediaStream = stream;
    video.srcObject   = stream;
    video.style.display  = 'block';
    noAccess.style.display = 'none';
  } catch (err) {
    console.warn('Camera error:', err);
    video.style.display     = 'none';
    noAccess.style.display  = 'flex';
  }
}

function stopCamera() {
  if (state.mediaStream) {
    state.mediaStream.getTracks().forEach(t => t.stop());
    state.mediaStream = null;
  }
  const video = document.getElementById('camera-video');
  video.srcObject = null;
}

function capturePhoto() {
  if (state.photos.length >= 3) return;

  const video  = document.getElementById('camera-video');
  const canvas = document.getElementById('camera-canvas');

  if (!video.videoWidth) { showToast('Camera chưa sẵn sàng, thử lại'); return; }

  canvas.width  = video.videoWidth;
  canvas.height = video.videoHeight;
  canvas.getContext('2d').drawImage(video, 0, 0);

  canvas.toBlob((blob) => {
    const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
    state.photos.push({ blob, dataUrl, fileUrl: null });
    updateCounter();
    renderCameraThumbs();

    if (state.photos.length >= 3) {
      stopCamera();
      setTimeout(goToReport, 350);
    }
  }, 'image/jpeg', 0.85);
}

function deletePhoto(index) {
  state.photos.splice(index, 1);
  updateCounter();
  renderCameraThumbs();
}

function updateCounter() {
  document.getElementById('photo-counter').textContent = `${state.photos.length} / 3`;
  const skipBtn = document.getElementById('btn-skip-camera');
  skipBtn.style.display = (state.photos.length > 0 && state.photos.length < 3) ? 'flex' : 'none';
}

function renderCameraThumbs() {
  document.getElementById('thumbnail-row').innerHTML = state.photos.map((p, i) => `
    <div class="thumb-item">
      <img src="${p.dataUrl}" alt="Ảnh ${i + 1}">
      <button class="thumb-delete" onclick="deletePhoto(${i})" aria-label="Xóa ảnh ${i + 1}">✕</button>
    </div>
  `).join('');
}

// ══════════════════════════════════════════════════════════
//  SCREEN 3 – REPORT
// ══════════════════════════════════════════════════════════
function setupReportScreen() {
  setupVoiceRecording();

  document.getElementById('voice-text').addEventListener('input', (e) => {
    state.voiceText = e.target.value;
  });

  document.getElementById('btn-submit').addEventListener('click', submitReport);
}

function goToReport() {
  document.getElementById('report-room-label').textContent = `PHÒNG ${state.roomId}`;
  document.getElementById('voice-text').value = state.voiceText;

  // Render thumbnails
  document.getElementById('report-thumbnails').innerHTML = state.photos.map((p, i) => `
    <img src="${p.dataUrl}" class="report-thumb" alt="Ảnh ${i + 1}">
  `).join('');

  showScreen('report');
}

// ── Voice Recording ────────────────────────────────────────
function setupVoiceRecording() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  const micBtn    = document.getElementById('btn-mic');
  const voiceLabel = document.getElementById('voice-label');
  const waves     = document.getElementById('voice-waves');

  if (!SR) {
    micBtn.style.opacity = '0.45';
    micBtn.style.cursor  = 'not-allowed';
    voiceLabel.textContent = 'Không hỗ trợ';
    return;
  }

  const rec = new SR();
  rec.lang              = 'vi-VN';
  rec.continuous        = false;
  rec.interimResults    = true;
  state.recognition     = rec;

  let baseText = '';

  rec.onresult = (e) => {
    let interim = '';
    for (let i = e.resultIndex; i < e.results.length; i++) {
      e.results[i].isFinal
        ? (baseText += e.results[i][0].transcript)
        : (interim  += e.results[i][0].transcript);
    }
    const ta = document.getElementById('voice-text');
    ta.value        = baseText + interim;
    state.voiceText = ta.value;
  };

  rec.onend = () => {
    state.isRecording = false;
    micBtn.classList.remove('recording');
    waves.classList.remove('active');
    voiceLabel.textContent = 'Nhấn để ghi âm';
    state.voiceText = document.getElementById('voice-text').value;
  };

  rec.onerror = (e) => {
    state.isRecording = false;
    micBtn.classList.remove('recording');
    waves.classList.remove('active');
    voiceLabel.textContent = 'Nhấn để ghi âm';
    if (e.error !== 'no-speech') showToast('Lỗi ghi âm: ' + e.error);
  };

  micBtn.addEventListener('click', () => {
    if (state.isRecording) {
      rec.stop();
    } else {
      baseText = document.getElementById('voice-text').value;
      try {
        rec.start();
        state.isRecording = true;
        micBtn.classList.add('recording');
        waves.classList.add('active');
        voiceLabel.textContent = 'Đang ghi… nhấn để dừng';
      } catch (err) {
        showToast('Không thể bắt đầu ghi âm');
      }
    }
  });
}

// ── Submit ─────────────────────────────────────────────────
async function submitReport() {
  if (state.photos.length === 0) { showToast('Vui lòng chụp ít nhất 1 ảnh'); return; }
  if (state.isSubmitting) return;

  state.isSubmitting = true;
  const btn = document.getElementById('btn-submit');
  btn.disabled    = true;
  btn.textContent = 'Đang gửi…';

  try {
    // Upload photos to S3 (skip if already uploaded)
    for (const photo of state.photos) {
      if (!photo.fileUrl) {
        try {
          const { upload_url, file_url } = await api.post('/api/upload/presigned-url', {
            filename: `hk_${state.roomId}_${Date.now()}.jpg`,
          });
          await fetch(upload_url, {
            method: 'PUT',
            body: photo.blob,
            headers: { 'Content-Type': 'image/jpeg' },
          });
          photo.fileUrl = file_url;
        } catch (uploadErr) {
          console.warn('S3 upload skipped (dev mode):', uploadErr.message);
          photo.fileUrl = `local://${Date.now()}`;
        }
      }
    }

    // POST report
    await api.post('/api/reports', {
      room_id:    state.roomId,
      note:       state.voiceText || null,
      image_urls: state.photos.map(p => p.fileUrl),
    });

    // Go to success
    document.getElementById('success-room-text').textContent =
      `Phòng ${state.roomId} đã được ghi nhận`;
    showScreen('success');
    startSuccessCountdown();

  } catch (err) {
    showToast('Lỗi: ' + err.message);
  } finally {
    state.isSubmitting = false;
    btn.disabled       = false;
    btn.innerHTML      = '✓ GỬI BÁO CÁO';
  }
}

// ══════════════════════════════════════════════════════════
//  SCREEN 4 – SUCCESS
// ══════════════════════════════════════════════════════════
function setupSuccessScreen() {
  document.getElementById('btn-new-room').addEventListener('click', resetApp);
}

function startSuccessCountdown() {
  if (state.countdownTimer) clearInterval(state.countdownTimer);
  let secs = 3;
  const numEl = document.getElementById('countdown-num');
  if (numEl) numEl.textContent = secs;

  state.countdownTimer = setInterval(() => {
    secs--;
    if (numEl) numEl.textContent = secs;
    if (secs <= 0) {
      clearInterval(state.countdownTimer);
      if (document.getElementById('screen-success').classList.contains('active')) {
        resetApp();
      }
    }
  }, 1000);
}

function resetApp() {
  if (state.countdownTimer) { clearInterval(state.countdownTimer); state.countdownTimer = null; }
  if (state.isRecording && state.recognition) {
    try { state.recognition.abort(); } catch (e) { /* ignore */ }
  }
  stopCamera();

  state.roomId      = '';
  state.photos      = [];
  state.voiceText   = '';
  state.isRecording = false;

  const roomInput = document.getElementById('room-input');
  roomInput.value = '';
  document.getElementById('btn-continue-room').disabled = true;
  document.getElementById('voice-text').value = '';
  document.getElementById('thumbnail-row').innerHTML = '';

  showScreen('room');
  setTimeout(() => roomInput.focus(), 200);
}

